import xml.etree.ElementTree as ET

def parse_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    data = {}
    
    for child in root:
        if len(child) == 0:  # check for leaf nodes
            data[child.tag] = child.text
            
    return data